function validateStock(requiredMap, stockArray) {
  const result = {
    isPass: true,     // 最终是否通过
    errors: [],       // 记录具体的错误信息
    missingSkus: [],  // 记录数组里根本没找到的料号
    shortageSkus: []  // 记录找到了但数量不够的料号
  };

  // 1. 优化性能：将库存数组转为以 sku_code 为 key 的 Map 或对象
  // 这样查找的时间复杂度从 O(n) 降为 O(1)
  const stockMap = new Map();
  stockArray.forEach(item => {
    // 假设 sku_code 唯一，如果有重复需要累加 qty
    const currentQty = stockMap.get(item.sku_code) || 0;
    stockMap.set(item.sku_code, currentQty + item.qty);
  });

  // 2. 遍历需求 Map 进行比对
  requiredMap.forEach((reqQty, reqSku) => {

    // A. 校验是否存在
    if (!stockMap.has(reqSku)) {
      result.isPass = false;
      result.missingSkus.push(reqSku);
      result.errors.push(`【缺失】料号 ${reqSku} 在订单中不存在。`);
      return; // 进入下一次循环
    }

    // B. 校验数量是否足够 (需求量 <= 库存量)
    const stockQty = stockMap.get(reqSku);
    if (reqQty > stockQty) {
      result.isPass = false;
      result.shortageSkus.push({ sku: reqSku, required: reqQty, stock: stockQty });
      result.errors.push(`【缺货】料号 ${reqSku} 库存不足。扫描: ${reqQty}, 需求: ${stockQty}`);
    }
  });

  return result;
}
