// 获取所有输入数据
const items = $input.all();
const results = [];

for (const item of items) {
  const originBody = item.json.body;
  const rawSnIds = originBody.snIds;

  // 1. 数据防错处理：如果没有 snIds，直接跳过
  if (!rawSnIds) continue;

  // 2. 清洗字符串：去掉所有的中文逗号、英文逗号和空格
  // 原字符串："S51AP10485W92C006187，" -> "S51AP10485W92C006187"
  const cleanString = rawSnIds.toString().replace(/[，,\s]/g, '');

  // 3. 按照固定长度 10 拆分
  // match(/.{1,10}/g) 会把字符串每10位切成数组的一个元素
  const snArray = cleanString.match(/.{1,10}/g) || [];

  // 4. 生成新数据（拆分出几条SN，就生成几条数据）
  for (const sn of snArray) {
    results.push({
      json: {
        body: {
          code: originBody.code,           // 保留原 code
          channelId: originBody.channelId, // 保留原 channelId
          snIds: sn                        // 放入切分好的单个 SN
        }
      }
    });
  }
}

return results;
